@startuml
title Gson源码 策略模式+工厂方法模式

class "Gson" as Gson {
  [C]
  factories:List<TypeAdapterFactory>
  fromJson(String):Object
  toJson(Object):String
}

interface "TypeAdapter" as TypeAdapter {
  [I]
  read()
  write()
}

interface "TypeAdapterFactory" as TypeAdapterFactory {
  [I]
  create(Gson gson, TypeToken<T> type) : <T> TypeAdapter<T>
}

Gson ..> TypeAdapterFactory : 1..*
TypeAdapterFactory ..> TypeAdapter

@enduml
